package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.PrintStream;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrinterReturnsCSVPrinter() throws IOException {
        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);
    }

    @Test
    void testPrinterWritesToSystemOut() throws Exception {
        // Use reflection to access the private constructor of CSVPrinter to spy on it
        // Since CSVPrinter constructor is public, but we want to verify the output stream is System.out
        // We'll use the printer() method and verify the underlying Appendable is System.out

        CSVPrinter printer = csvFormat.printer();

        // Use reflection to access the 'out' field of CSVPrinter to verify it is System.out
        var outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);
        Object outObject = outField.get(printer);

        assertTrue(outObject instanceof PrintStream || outObject instanceof Appendable);

        // System.out is a PrintStream, but CSVPrinter accepts Appendable, System.out can be wrapped
        // So just verify that the outObject is System.out or wraps System.out
        if (outObject instanceof PrintStream) {
            assertSame(System.out, outObject);
        }
    }
}
